using System.ComponentModel;
using Microsoft.Extensions.AI;

namespace ResearchAgent;

/// <summary>
/// A note-taking tool that stores research findings during an agent session.
/// </summary>
public sealed class Notepad
{
    private readonly List<NoteEntry> _notes = [];

    public IReadOnlyList<NoteEntry> Notes => _notes;

    [Description("Saves a research note with a title and body. Use this to record key findings.")]
    public string AddNote(
        [Description("Short title summarizing the note")] string title,
        [Description("Detailed content of the note")] string body)
    {
        var entry = new NoteEntry(title, body, DateTime.UtcNow);
        _notes.Add(entry);
        return $"Note saved: \"{title}\" ({_notes.Count} total notes)";
    }

    [Description("Retrieves all saved research notes.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n\n", _notes.Select((n, i) =>
            $"[{i + 1}] {n.Title}\n{n.Body}"));
    }
}

public sealed record NoteEntry(string Title, string Body, DateTime Timestamp);

using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;

namespace ResearchAgent;

/// <summary>
/// A web search tool that queries a search API.
/// Uses a simulated search when no API key is configured.
/// </summary>
public static class WebSearchTool
{
    [Description("Searches the web for information on a query. Returns a list of relevant results with titles, snippets, and URLs.")]
    public static async Task<string> SearchWebAsync(
        [Description("The search query to look up")] string query,
        [Description("Maximum number of results to return (1-5)")] int maxResults = 3,
        CancellationToken cancellationToken = default)
    {
        maxResults = Math.Clamp(maxResults, 1, 5);

        // Check for a real search API key (e.g., Bing Search API)
        var bingKey = Environment.GetEnvironmentVariable("BING_SEARCH_API_KEY");

        if (!string.IsNullOrEmpty(bingKey))
        {
            return await SearchWithBingAsync(query, maxResults, bingKey, cancellationToken);
        }

        // Fallback: simulated search results for demonstration
        return GetSimulatedResults(query, maxResults);
    }

    private static async Task<string> SearchWithBingAsync(
        string query, int maxResults, string apiKey, CancellationToken ct)
    {
        using var http = new HttpClient();
        http.DefaultRequestHeaders.Add("Ocp-Apim-Subscription-Key", apiKey);

        var url = $"https://api.bing.microsoft.com/v7.0/search?q={Uri.EscapeDataString(query)}&count={maxResults}";

        try
        {
            var response = await http.GetFromJsonAsync<JsonElement>(url, ct);
            var webPages = response.GetProperty("webPages").GetProperty("value");

            var results = new List<string>();
            foreach (var page in webPages.EnumerateArray().Take(maxResults))
            {
                var title = page.GetProperty("name").GetString();
                var snippet = page.GetProperty("snippet").GetString();
                var pageUrl = page.GetProperty("url").GetString();
                results.Add($"Title: {title}\nSnippet: {snippet}\nURL: {pageUrl}");
            }

            return string.Join("\n---\n", results);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Retrying may help.";
        }
    }

    private static string GetSimulatedResults(string query, int maxResults)
    {
        var simulatedResults = new[]
        {
            new { Title = $"Overview of {query}", Snippet = $"A comprehensive introduction to {query}, covering its history, key concepts, and current state of the art. This resource provides foundational knowledge for understanding the topic.", Url = $"https://example.com/{Uri.EscapeDataString(query)}/overview" },
            new { Title = $"Recent advances in {query}", Snippet = $"Research published in 2025 shows significant progress in {query}. New methodologies and frameworks have emerged that push the boundaries of what was previously possible.", Url = $"https://example.com/{Uri.EscapeDataString(query)}/advances" },
            new { Title = $"Practical applications of {query}", Snippet = $"Industry adoption of {query} has accelerated, with applications spanning healthcare, finance, and manufacturing. Case studies demonstrate measurable ROI.", Url = $"https://example.com/{Uri.EscapeDataString(query)}/applications" },
            new { Title = $"Challenges and limitations of {query}", Snippet = $"While promising, {query} faces challenges including scalability concerns, ethical considerations, and the need for specialized expertise.", Url = $"https://example.com/{Uri.EscapeDataString(query)}/challenges" },
            new { Title = $"Future directions for {query}", Snippet = $"Experts predict {query} will evolve significantly over the next decade, with emerging trends pointing toward greater integration with other technologies.", Url = $"https://example.com/{Uri.EscapeDataString(query)}/future" },
        };

        var results = simulatedResults.Take(maxResults)
            .Select(r => $"Title: {r.Title}\nSnippet: {r.Snippet}\nURL: {r.Url}");

        return "[Simulated results — set BING_SEARCH_API_KEY for live search]\n\n"
            + string.Join("\n---\n", results);
    }
}

using Microsoft.Extensions.AI;

namespace ResearchAgent;

/// <summary>
/// Orchestrates the research agent, providing it with tools and a system prompt.
/// </summary>
public sealed class ResearchService(IChatClient chatClient, Notepad notepad)
{
    private const int MaxIterations = 15;

    public async Task ResearchAsync(string topic, CancellationToken ct)
    {
        var tools = new AITool[]
        {
            AIFunctionFactory.Create(WebSearchTool.SearchWebAsync),
            AIFunctionFactory.Create(notepad.AddNote),
            AIFunctionFactory.Create(notepad.GetAllNotes),
        };

        var systemPrompt = $"""
            You are a research agent. Your goal is to thoroughly research the following topic 
            and produce a well-organized summary.

            Topic: {topic}

            Instructions:
            1. Search the web for information about the topic (use multiple queries to cover 
               different aspects).
            2. As you find useful information, save notes using the AddNote tool with clear 
               titles and detailed content.
            3. After gathering enough information (at least 3 different aspects), retrieve 
               all your notes and write a final comprehensive summary.
            4. Present the final summary to the user with clear sections and key takeaways.

            Be thorough but concise. Cite sources where possible.
            """;

        var messages = new List<ChatMessage>
        {
            new(ChatRole.System, systemPrompt),
            new(ChatRole.User, $"Please research: {topic}")
        };

        var options = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
            Tools = tools,
        };

        int iteration = 0;
        while (iteration < MaxIterations)
        {
            iteration++;

            var response = await chatClient.GetResponseAsync(messages, options, ct);

            // Add all response messages to history
            foreach (var msg in response.Messages)
            {
                messages.Add(msg);
            }

            // Check if we're done (no more tool calls pending)
            if (response.FinishReason == ChatFinishReason.Stop)
            {
                // Print the final response
                var lastAssistant = response.Messages
                    .LastOrDefault(m => m.Role == ChatRole.Assistant);

                if (lastAssistant?.Text is { Length: > 0 } text)
                {
                    Console.WriteLine("═══════════════════════════════════════════════════");
                    Console.WriteLine(" RESEARCH SUMMARY");
                    Console.WriteLine("═══════════════════════════════════════════════════");
                    Console.WriteLine(text);
                    Console.WriteLine("═══════════════════════════════════════════════════");
                }
                break;
            }

            Console.WriteLine($"  [Agent working... iteration {iteration}]");
        }

        if (iteration >= MaxIterations)
        {
            Console.WriteLine("\n⚠️  Agent reached maximum iterations. Partial results:");
            Console.WriteLine(notepad.GetAllNotes());
        }

        Console.WriteLine($"\n📝 Total notes taken: {notepad.Notes.Count}");
    }
}

