using System.ComponentModel;
using Microsoft.Extensions.AI;

namespace ResearchAgent;

/// <summary>
/// A note-taking tool that stores research findings during an agent session.
/// </summary>
public sealed class Notepad
{
    private readonly List<NoteEntry> _notes = [];

    public IReadOnlyList<NoteEntry> Notes => _notes;

    [Description("Saves a research note with a title and body. Use this to record key findings.")]
    public string AddNote(
        [Description("Short title summarizing the note")] string title,
        [Description("Detailed content of the note")] string body)
    {
        var entry = new NoteEntry(title, body, DateTime.UtcNow);
        _notes.Add(entry);
        return $"Note saved: \"{title}\" ({_notes.Count} total notes)";
    }

    [Description("Retrieves all saved research notes.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n\n", _notes.Select((n, i) =>
            $"[{i + 1}] {n.Title}\n{n.Body}"));
    }
}

public sealed record NoteEntry(string Title, string Body, DateTime Timestamp);

