/// <summary>
/// A web search tool that queries a search API.
/// Uses a simulated search when no API key is configured.
/// </summary>
public static class WebSearchTool
{
    [Description("Searches the web for information on a query. Returns a list of relevant results with titles, snippets, and URLs.")]
    public static async Task<string> SearchWebAsync(
        [Description("The search query to look up")] string query,
        [Description("Maximum number of results to return (1-5)")] int maxResults = 3,
        CancellationToken cancellationToken = default)
    {
        maxResults = Math.Clamp(maxResults, 1, 5);

        // Check for a real search API key (e.g., Bing Search API)
        var bingKey = Environment.GetEnvironmentVariable("BING_SEARCH_API_KEY");

        if (!string.IsNullOrEmpty(bingKey))
        {
            return await SearchWithBingAsync(query, maxResults, bingKey, cancellationToken);
        }

        // Fallback: simulated search results for demonstration
        return GetSimulatedResults(query, maxResults);
    }

    private static async Task<string> SearchWithBingAsync(
        string query, int maxResults, string apiKey, CancellationToken ct)
    {
        using var http = new HttpClient();
        http.DefaultRequestHeaders.Add("Ocp-Apim-Subscription-Key", apiKey);

        var url = $"https://api.bing.microsoft.com/v7.0/search?q={Uri.EscapeDataString(query)}&count={maxResults}";

        try
        {
            var response = await http.GetFromJsonAsync<JsonElement>(url, ct);
            var webPages = response.GetProperty("webPages").GetProperty("value");

            var results = new List<string>();
            foreach (var page in webPages.EnumerateArray().Take(maxResults))
            {
                var title = page.GetProperty("name").GetString();
                var snippet = page.GetProperty("snippet").GetString();
                var pageUrl = page.GetProperty("url").GetString();
                results.Add($"Title: {title}\nSnippet: {snippet}\nURL: {pageUrl}");
            }

            return string.Join("\n---\n", results);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Retrying may help.";
        }
    }

