using Microsoft.Extensions.AI;

namespace ResearchAgent;

/// <summary>
/// Orchestrates the research agent, providing it with tools and a system prompt.
/// </summary>
public sealed class ResearchService(IChatClient chatClient, Notepad notepad)
{
    private const int MaxIterations = 15;

    public async Task ResearchAsync(string topic, CancellationToken ct)
    {
        var tools = new AITool[]
        {
            AIFunctionFactory.Create(WebSearchTool.SearchWebAsync),
            AIFunctionFactory.Create(notepad.AddNote),
            AIFunctionFactory.Create(notepad.GetAllNotes),
        };

        var systemPrompt = $"""
            You are a research agent. Your goal is to thoroughly research the following topic 
            and produce a well-organized summary.

            Topic: {topic}

            Instructions:
            1. Search the web for information about the topic (use multiple queries to cover 
               different aspects).
            2. As you find useful information, save notes using the AddNote tool with clear 
               titles and detailed content.
            3. After gathering enough information (at least 3 different aspects), retrieve 
               all your notes and write a final comprehensive summary.
            4. Present the final summary to the user with clear sections and key takeaways.

            Be thorough but concise. Cite sources where possible.
            """;

        var messages = new List<ChatMessage>
        {
            new(ChatRole.System, systemPrompt),
            new(ChatRole.User, $"Please research: {topic}")
        };

        var options = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
            Tools = tools,
        };

        int iteration = 0;
        while (iteration < MaxIterations)
        {
            iteration++;

            var response = await chatClient.GetResponseAsync(messages, options, ct);

            // Add all response messages to history
            foreach (var msg in response.Messages)
            {
                messages.Add(msg);
            }

            // Check if we're done (no more tool calls pending)
            if (response.FinishReason == ChatFinishReason.Stop)
            {
                // Print the final response
                var lastAssistant = response.Messages
                    .LastOrDefault(m => m.Role == ChatRole.Assistant);

                if (lastAssistant?.Text is { Length: > 0 } text)
                {
                    Console.WriteLine("═══════════════════════════════════════════════════");
                    Console.WriteLine(" RESEARCH SUMMARY");
                    Console.WriteLine("═══════════════════════════════════════════════════");
                    Console.WriteLine(text);
                    Console.WriteLine("═══════════════════════════════════════════════════");
                }
                break;
            }

            Console.WriteLine($"  [Agent working... iteration {iteration}]");
        }

        if (iteration >= MaxIterations)
        {
            Console.WriteLine("\n⚠️  Agent reached maximum iterations. Partial results:");
            Console.WriteLine(notepad.GetAllNotes());
        }

        Console.WriteLine($"\n📝 Total notes taken: {notepad.Notes.Count}");
    }
}

